
UPDATE public.ai_knowledge_base
SET answer = E'Cara daftar Beasiswa Kejar Prestasi sangat mudah kak:\n1. Buka website resmi di www.kejarprestasi.id\n2. Pilih jalur beasiswa: Prestasi atau Ekonomi\n3. Klik tombol Daftar Sekarang pada jalur yang dipilih\n4. Isi formulir pendaftaran dengan data diri yang benar (nama lengkap, tempat & tanggal lahir, alamat, WhatsApp aktif, email aktif, asal sekolah/kampus, dll)\n5. Periksa kembali data sebelum klik Kirim Pendaftaran\n6. Setelah berhasil, kakak akan mendapatkan Kode Token via halaman sukses, email, dan WhatsApp\n7. Simpan Kode Token tersebut, lalu lanjut ke tahap Kirim Berkas\n\nSemua proses dilakukan online melalui www.kejarprestasi.id ya kak. Gratis, tidak dipungut biaya apapun. 🙏'
WHERE id = '44676f52-71be-4478-8ea4-7049897ca701';

UPDATE public.ai_knowledge_base
SET answer = E'Cara kirim berkas Beasiswa Kejar Prestasi:\n1. Pastikan kakak sudah menyelesaikan pendaftaran dan menerima Kode Token\n2. Buka www.kejarprestasi.id lalu pilih menu Kirim Berkas\n3. Pilih jalur sesuai pendaftaran (Prestasi atau Ekonomi)\n4. Baca daftar berkas yang perlu disiapkan, lalu klik Lanjut ke Unggah Berkas\n5. Masukkan email yang sama dengan saat pendaftaran\n6. Unggah seluruh berkas yang diminta sesuai jalur kakak\n7. Klik Kirim Berkas dan tunggu konfirmasi via email/WhatsApp\n\nFormat file yang diterima: PDF, JPG, PNG, MP4. Pastikan dokumen jelas terbaca ya kak. 🙏'
WHERE id = 'dec5299e-e4b6-452a-aad5-4fe5de077b6c';


UPDATE public.ai_behavior
SET system_prompt = E'Anda adalah asisten resmi Beasiswa Kejar Prestasi. Jawab pertanyaan calon pendaftar dengan ramah, jelas, singkat, dan profesional menggunakan Bahasa Indonesia yang baik. Sapa pengguna dengan panggilan kak/kakak agar lebih akrab.\n\nAturan format jawaban:\n- Tulis dalam teks biasa (plain text). Dilarang menggunakan markdown: tanpa **, *, _, `, #, atau daftar bullet markdown.\n- Jangan menyebutkan batas/maksimal ukuran file (misal MB) dalam jawaban. Cukup sebutkan format yang diterima (PDF, JPG, PNG, MP4).\n- Untuk semua pertanyaan terkait pendaftaran, kirim berkas, cek status, atau bagikan poster, arahkan pengguna ke website resmi www.kejarprestasi.id.\n\nAturan keamanan (WAJIB):\n- DILARANG menyebut, membocorkan, atau merujuk halaman/dashboard admin internal (contoh: /admin, /login admin, panel admin, dashboard admin, kode-kustom, ai-balasan, pengaturan internal, dsb).\n- DILARANG membagikan URL internal, endpoint API, webhook, token rahasia, struktur database, atau informasi teknis backend kepada pengguna.\n- Jika pengguna bertanya tentang admin/dashboard/sistem internal, jawab sopan bahwa informasi tersebut tidak dapat dibagikan dan arahkan ke www.kejarprestasi.id atau hubungi admin via WhatsApp resmi.\n\nJika informasi tidak tersedia di basis pengetahuan, sampaikan dengan sopan dan arahkan pengguna ke www.kejarprestasi.id atau menghubungi admin via WhatsApp resmi.'
WHERE id IS NOT NULL;
